import { Component } from 'react';

import BpkButton, { BUTTON_TYPES } from '../../bpk-component-button';
import { cssModules } from '../../bpk-react-utils';

import BpkProgress from './BpkProgress';

import STYLES from './BpkProgress.stories.module.scss';

const getClassName = cssModules(STYLES);

type ProgressContainerProps = {
  small?: boolean;
};

type ProgressContainerState = {
  progress: number;
};

class ProgressContainer extends Component<
  ProgressContainerProps,
  ProgressContainerState
> {
  constructor(props: ProgressContainerProps) {
    super(props);

    this.state = {
      progress: 0,
    };
  }

  render() {
    const { progress } = this.state;
    return (
      <div className={getClassName('bpkdocs-progress-container__flex')}>
        <BpkButton
          type={BUTTON_TYPES.secondary}
          onClick={() => this.setState({ progress: 0 })}
          disabled={progress === 0}
        >
          Reset
        </BpkButton>
        &nbsp;
        <BpkButton
          onClick={() => this.setState({ progress: progress + 50 })}
          disabled={progress === 100}
        >
          Go!
        </BpkButton>
        &nbsp;
        <div className={getClassName('bpkdocs-progress-container__flex-grow')}>
          <BpkProgress min={0} max={100} value={progress} {...this.props} />
        </div>
      </div>
    );
  }
}

type SteppedProgressContainerState = {
  progress: number;
};

class SteppedProgressContainer extends Component<
  {},
  SteppedProgressContainerState
> {
  constructor(props: {}) {
    super(props);

    this.state = {
      progress: 1,
    };
  }

  setProgress = (progress: number) => {
    if (progress >= 1 && progress <= 5) {
      this.setState({ progress });
    }
  };

  render() {
    return (
      <div>
        <BpkProgress
          min={0}
          max={5}
          value={this.state.progress}
          stepped
          {...this.props}
        />
        <br />
        <div className={getClassName('bpkdocs-progress-container__flex')}>
          <BpkButton
            type={BUTTON_TYPES.secondary}
            onClick={() => this.setProgress(this.state.progress - 1)}
            disabled={this.state.progress <= 1}
          >
            Back
          </BpkButton>
          <span>{`Step ${this.state.progress} of 5`}</span>
          <BpkButton
            onClick={() => this.setProgress(this.state.progress + 1)}
            disabled={this.state.progress === 5}
          >
            Continue
          </BpkButton>
        </div>
      </div>
    );
  }
}

const DefaultExample = () => <ProgressContainer />;

const SmallExample = () => <ProgressContainer small />;

const SteppedExample = () => <SteppedProgressContainer />;

const MixedExample = () => (
  <div>
    <DefaultExample />
    <SmallExample />
    <SteppedExample />
  </div>
);

const meta = {
  title: 'bpk-component-progress',
  component: BpkProgress,
};

export default meta;

export const Default = {
  render: () => <DefaultExample />,
};

export const Small = {
  render: () => <SmallExample />,
};

export const Stepped = {
  render: () => <SteppedExample />,
};

export const VisualTest = {
  render: () => <MixedExample />,
};

export const VisualTestWithZoom = {
  render: () => <MixedExample />,
  args: {
    zoomEnabled: true,
  },
};
